// 注册一个内置插件示例
registerBuiltinPlugin({
  name: 'team-workflow',
  description: 'Team-specific development workflows',
  version: '1.0.0',
  defaultEnabled: true,
  isAvailable: () => process.env.TEAM_ID !== undefined,
  skills: [
    {
      name: 'team-review',
      description: 'Run team-specific code review checks',
      allowedTools: ['Read', 'Grep', 'Bash'],
      getPromptForCommand: async (args) => {
        const teamConfig = await loadTeamConfig()
        return [{ type: 'text', text: buildReviewPrompt(teamConfig) }]
      },
    },
  ],
  hooks: {
    beforeToolUse: {
      Bash: 'run-team-precheck',
    },
  },
})
